using Microsoft.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// Train model at startup
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features",
        "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers
        .SdcaLogisticRegression(labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(dataView);

// Evaluate
var predictions = model.Transform(dataView);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model Accuracy: {metrics.Accuracy:P2}");
Console.WriteLine($"Model AUC:      {metrics.AreaUnderRocCurve:P2}");

var predictionEngine = mlContext.Model
    .CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

app.MapGet("/", () => "ChurnPredictor API – POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        churned = prediction.Churned,
        probability = prediction.Probability
    });
});

app.Run();

record PredictRequest(float Age, float Income, string Region, float PurchaseHistory);

